// Extract structured disbursement data from email body
const item = $input.item.json;
const body = (item.text || item.snippet || '').trim();
const subject = item.subject || '';
const sender = item.from || '';
const date = item.date || new Date().toISOString();

// ── Regex extractors ────────────────────────────────────────────────────────

// Amount: e.g. "25,000,000 MMK" or "Amount: 15,000,000 MMK"
const amountMatch = body.match(/([\d,]+(?:\.\d+)?)\s*MMK/i)
  || body.match(/Amount[:\s]+([\d,]+(?:\.\d+)?)/i);
const amount = amountMatch ? amountMatch[1].replace(/,/g, '') : null;

// Company: e.g. "Acme Innovations Inc" or "Company: XYZ Ltd"
const companyMatch = body.match(/Company[:\s]+([^\n]+)/i)
  || subject.match(/Salary Disbursement[\s\-–]+([^\n]+)/i);
const company = companyMatch ? companyMatch[1].trim() : null;

// Payroll period: e.g. "February 1-15, 2024" or "Period: March 2024"
const periodMatch = body.match(/(?:Payroll Period|Payment Period|Period)[:\s]+([^\n]+)/i)
  || body.match(/(January|February|March|April|May|June|July|August|September|October|November|December)[^\n,]*/i);
const period = periodMatch ? periodMatch[1].trim() : null;

// Number of employees
const employeesMatch = body.match(/(?:Number of employees|Total employees|employees)[:\s]+(\d+)/i);
const employees = employeesMatch ? parseInt(employeesMatch[1]) : null;

// Payment type
const paymentTypeMatch = body.match(/(?:Payment Type|Method|Disbursement Method)[:\s]+([^\n]+)/i)
  || body.match(/(SalaryToMA|Direct Wallet Transfer|Bank Transfer)/i);
const paymentType = paymentTypeMatch ? paymentTypeMatch[1].trim() : null;

// Approvers
const approverMatches = [...body.matchAll(/[-–]\s+([^,\n]+),\s+[^—]+—\s+Approved/gi)];
const approvers = approverMatches.map(m => m[1].trim());

// Attachment info
const attachmentKeys = Object.keys(item).filter(k => k.startsWith('attachment_'));
const attachmentCount = attachmentKeys.length;

return {
  json: {
    // Raw email metadata
    messageId: item.id,
    threadId: item.threadId,
    subject,
    sender,
    date,
    labels: item.labelIds || [],

    // Extracted structured fields
    disbursement: {
      company,
      amount_mmk: amount ? Number(amount) : null,
      period,
      employees,
      payment_type: paymentType,
      approvers: approvers.length ? approvers : null,
    },

    // Body content
    body_text: body,
    body_html: item.html || null,

    // Attachment metadata
    has_attachments: attachmentCount > 0,
    attachment_count: attachmentCount,
    attachment_keys: attachmentKeys,
  },
  // Pass through binary attachment data unchanged
  binary: $input.item.binary || {},
};

// Log and prepare email with attachments for downstream processing
const item = $input.item;
const json = item.json;
const binary = item.binary || {};

// Build attachment summary
const attachments = json.attachment_keys.map(key => ({
  key,
  filename: binary[key]?.fileName || key,
  mime_type: binary[key]?.mimeType || 'application/octet-stream',
  size_bytes: binary[key]?.fileSize || null,
}));

console.log(`[Disbursement] Email with ${attachments.length} attachment(s) from: ${json.sender}`);
console.log(`[Disbursement] Subject: ${json.subject}`);
console.log(`[Disbursement] Attachments:`, attachments.map(a => a.filename).join(', '));

return {
  json: {
    ...json,
    attachments,
    processing_status: 'extracted_with_attachments',
    processed_at: new Date().toISOString(),
  },
  binary,
};

// Log and prepare email without attachments
const json = $input.item.json;

console.log(`[Disbursement] Email (no attachments) from: ${json.sender}`);
console.log(`[Disbursement] Subject: ${json.subject}`);

return {
  json: {
    ...json,
    attachments: [],
    processing_status: 'extracted_body_only',
    processed_at: new Date().toISOString(),
  },
};

// Final output: log the fully processed disbursement record
const json = $input.item.json;

console.log('=== DISBURSEMENT RECORD ===');
console.log(JSON.stringify({
  subject: json.subject,
  sender: json.sender,
  date: json.date,
  disbursement: json.disbursement,
  has_attachments: json.has_attachments,
  attachment_count: json.attachment_count,
  status: json.processing_status,
}, null, 2));

// Return as-is for downstream nodes (webhook, database, Slack, etc.)
return $input.item;
